import{_ as e,a,b as i,c as s}from"./chunks/acesNark.CWowxZ7N.js";import{c as n,Q as l,j as o,m as d}from"./chunks/framework.D5MFXpji.js";const y=JSON.parse('{"title":"Tone Mapping","description":"","frontmatter":{"title":"Tone Mapping","order":3},"headers":[],"relativePath":"ko/post-effect/tone-mapping.md","filePath":"ko/post-effect/tone-mapping.md","lastUpdated":1781142511000}'),r={name:"ko/post-effect/tone-mapping.md"};function p(h,t,g,c,k,f){return l(),o("div",null,[...t[0]||(t[0]=[d(`<h1 id="톤-매핑-tone-mapping" tabindex="-1">톤 매핑 (Tone Mapping) <a class="header-anchor" href="#톤-매핑-tone-mapping" aria-label="Permalink to &quot;톤 매핑 (Tone Mapping)&quot;">​</a></h1><p>톤 매핑은 HDR(High Dynamic Range) 이미지의 넓은 밝기 범위를 표준 디바이스(LDR)에서 표현 가능한 범위로 자연스럽게 변환하는 필수적인 후처리 기법입니다. 씬의 전체적인 노출, 대비, 색감을 최종 조율하여 렌더링 결과물의 완성도를 결정합니다.</p><h2 id="_1-동작-원리-스마트-톤-매핑-전환-smart-transition" tabindex="-1">1. 동작 원리: 스마트 톤 매핑 전환 (Smart Transition) <a class="header-anchor" href="#_1-동작-원리-스마트-톤-매핑-전환-smart-transition" aria-label="Permalink to &quot;1. 동작 원리: 스마트 톤 매핑 전환 (Smart Transition)&quot;">​</a></h2><p>RedGPU의 톤 매핑은 단순히 파이프라인의 시작 또는 끝에 고정되어 실행되지 않습니다. 효율적인 HDR 연산과 LDR 후처리 간의 전환을 위해 <code>PostEffectManager</code>가 내부적으로 타이밍을 자동으로 제어합니다.</p><ul><li><strong>HDR 영역 보존</strong>: 씬 렌더링 직후 <code>SkyAtmosphere</code>, <code>SSAO</code>, <code>SSR</code> 등 깊이 정보 및 광범위한 색역을 필요로 하는 효과들은 톤 매핑 이전의 <strong>HDR 원본 데이터 상태</strong>에서 계산됩니다.</li><li><strong>자동 전환 타이밍</strong>: 사용자가 추가한 일반 이펙트(<code>view.postEffectManager.addEffect()</code>) 루프를 순회하다가 <strong>최초의 LDR(Low Dynamic Range) 효과를 만나는 시점에 즉시</strong> 톤 매핑을 수행합니다.</li><li><strong>기본 예외 처리</strong>: 만약 일반 이펙트 체인 내에 LDR 효과가 하나도 등록되어 있지 않다면, 파이프라인 루프의 맨 마지막 단계에서 톤 매핑이 자동으로 적용됩니다.</li></ul><hr><h2 id="_2-tonemappingmanager-설정" tabindex="-1">2. ToneMappingManager 설정 <a class="header-anchor" href="#_2-tonemappingmanager-설정" aria-label="Permalink to &quot;2. ToneMappingManager 설정&quot;">​</a></h2><p>모든 톤 매핑 관련 매개변수는 <code>view.toneMappingManager</code> 속성들을 통해 동적으로 조절할 수 있습니다. <code>View3D</code> 인스턴스 생성 시 내장되므로 직접 생성할 필요가 없습니다.</p><h3 id="_2-1-속성-정보" tabindex="-1">2.1 속성 정보 <a class="header-anchor" href="#_2-1-속성-정보" aria-label="Permalink to &quot;2.1 속성 정보&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">속성명</th><th style="text-align:left;">기본값</th><th style="text-align:left;">범위</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>mode</code></strong></td><td style="text-align:left;"><code>KHRONOS_PBR_NEUTRAL</code></td><td style="text-align:left;">-</td><td style="text-align:left;">톤 매핑 알고리즘 유형 (<code>RedGPU.ToneMapping.TONE_MAPPING_MODE</code>)</td></tr><tr><td style="text-align:left;"><strong><code>contrast</code></strong></td><td style="text-align:left;"><code>1.0</code></td><td style="text-align:left;"><code>0.0</code> ~ <code>2.0</code></td><td style="text-align:left;">명암 대비 강도</td></tr><tr><td style="text-align:left;"><strong><code>brightness</code></strong></td><td style="text-align:left;"><code>0.0</code></td><td style="text-align:left;"><code>-1.0</code> ~ <code>1.0</code></td><td style="text-align:left;">암부 및 명부의 부가적인 밝기 보정</td></tr></tbody></table><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 대비와 밝기를 미세하게 조정하여 시각 효과 강조</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> tm</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> view.toneMappingManager;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">tm.contrast </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1.05</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">tm.brightness </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0.02</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><hr><h2 id="_3-지원-알고리즘-tone-mapping-mode" tabindex="-1">3. 지원 알고리즘 (TONE_MAPPING_MODE) <a class="header-anchor" href="#_3-지원-알고리즘-tone-mapping-mode" aria-label="Permalink to &quot;3. 지원 알고리즘 (TONE_MAPPING_MODE)&quot;">​</a></h2><p>원하는 비주얼 스타일에 따라 톤 매핑 모드를 실시간으로 변경할 수 있습니다. 상수값은 <code>RedGPU.ToneMapping.TONE_MAPPING_MODE</code> 네임스페이스 하위에 선언되어 있습니다.</p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// ACES Filmic 알고리즘을 적용해 영화 같은 연출 적용</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">view.toneMappingManager.mode </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> RedGPU.ToneMapping.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">TONE_MAPPING_MODE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ACES_FILMIC_HILL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><table tabindex="0"><thead><tr><th style="text-align:left;">모드 상수</th><th style="text-align:left;">설명</th><th style="text-align:left;">비교 이미지</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>LINEAR</code></strong></td><td style="text-align:left;">아무런 보정을 거치지 않고 디바이스 범위로 출력합니다. 암부와 밝은 영역의 디테일 손실이 클 수 있습니다.</td><td style="text-align:left;"><img src="`+e+'" alt="Linear"></td></tr><tr><td style="text-align:left;"><strong><code>KHRONOS_PBR_NEUTRAL</code></strong></td><td style="text-align:left;">물리 기반 렌더링(PBR)의 색상 충실도를 유지하는 표준 알고리즘 (기본값)</td><td style="text-align:left;"><img src="'+a+'" alt="Khronos"></td></tr><tr><td style="text-align:left;"><strong><code>ACES_FILMIC_HILL</code></strong></td><td style="text-align:left;">시네마틱 영화 산업 표준인 ACES 알고리즘의 Hill 근사 버전으로 높은 대비를 만듭니다.</td><td style="text-align:left;"><img src="'+i+'" alt="ACES Hill"></td></tr><tr><td style="text-align:left;"><strong><code>ACES_FILMIC_NARKOWICZ</code></strong></td><td style="text-align:left;">ACES 알고리즘의 Narkowicz 수학적 근사 버전으로 더욱 드라마틱한 대비를 만듭니다.</td><td style="text-align:left;"><img src="'+s+'" alt="ACES Nark"></td></tr></tbody></table><hr><h2 id="_4-핵심-요약" tabindex="-1">4. 핵심 요약 <a class="header-anchor" href="#_4-핵심-요약" aria-label="Permalink to &quot;4. 핵심 요약&quot;">​</a></h2><ul><li>톤 매핑 설정은 <code>ToneMappingManager</code>가 담당하고, 실행 및 순서 전환은 <code>PostEffectManager</code>가 자동으로 최적화하여 처리합니다.</li><li>고품질 HDR 효과(SSAO, SSR) 연산 보존을 위해 이펙트 체인 진행 도중 스마트하게 분기하여 작동합니다.</li><li>물리적 정확도가 최우선인 씬에는 기본값인 <code>KHRONOS_PBR_NEUTRAL</code>을, 연출 중심의 씬에는 <code>ACES_FILMIC_</code> 계열을 권장합니다.</li></ul><h2 id="_5-다음-학습-추천" tabindex="-1">5. 다음 학습 추천 <a class="header-anchor" href="#_5-다음-학습-추천" aria-label="Permalink to &quot;5. 다음 학습 추천&quot;">​</a></h2><ul><li><strong><a href="./builtin-effects.html">빌트인 이펙트</a></strong> : 물리 기반 입체감을 부여하는 SSAO 및 실시간 SSR 활성화하기</li><li><strong><a href="./general-effects.html">일반 이펙트</a></strong> : 톤 매핑 전후 단계에 블룸, 블러, 그레이스케일 추가하기</li></ul>',21)])])}const m=n(r,[["render",p]]);export{y as __pageData,m as default};
